// an existing index's WHERE clause.
     sqlx::query("DROP INDEX IF EXISTS idx_knowledge_embedding")
         .execute(&self.pool)
         .await
         .map_err(|e| CorviaError::Storage(format!("Failed to drop old HNSW index: {e}")))?;

     sqlx::query(
         "CREATE INDEX IF NOT EXISTS idx_knowledge_embedding_active ON knowledge \
          USING hnsw (embedding vector_cosine_ops) WITH (m = 16, ef_construction = 64) \
          WHERE tier IN ('hot', 'warm')"
     )
         .execute(&self.pool)
         .await
         .map_err(|e| CorviaError::Storage(format!("Failed to create partial HNSW index: {e}")))?;

     // Tier index for fast scope+tier filtering.
     sqlx::query(
         "CREATE INDEX IF NOT EXISTS idx_knowledge_tier ON knowledge(scope_id, tier)"
     )
     .execute(&self.pool)
     .await
     .map_err(|e| CorviaError::Storage(format!("Failed to create tier index: {e}")))?;

     // Partial index for pinned entry queries (only indexes pinned rows).
     sqlx::query(
         "CREATE INDEX IF NOT EXISTS idx_knowledge_pinned ON knowledge(scope_id) WHERE pinned = true"
     )
     .execute(&self.pool)
     .await
     .map_err(|e| CorviaError::Storage(format!("Failed to create pinned index: {e}")))?;

     // Full-text search: tsvector column + GIN index (Phase 2b).
     // GENERATED ALWAYS AS stored column: tsvector updates automatically on
     // INSERT/UPDATE with zero application-side maintenance. Verified on PG 12+
     // (to_tsvector accepted despite STABLE volatility). English config only.
     sqlx::query(
         "ALTER TABLE knowledge ADD COLUMN IF NOT EXISTS tsv tsvector \
          GENERATED ALWAYS AS (to_tsvector('english', content)) STORED"
     )
     .execute(&self.pool)
     .await
     .map_err(|e| CorviaError::Storage(format!("Failed to add tsvector column: {e}")))?;

     sqlx::query(
         "CREATE INDEX IF NOT EXISTS idx_knowledge_fts ON knowledge USING GIN (tsv)"
     )
